def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        if capacity < item:
            continue
        ratio = item / capacity
        base_score = 0
        if ratio == 1:
            base_score = 0
        elif ratio > 0.9:
            base_score = (1 - ratio) * 10
        elif ratio > 0.5:
            base_score = (0.7 - ratio) ** 3 * 20
        else:
            base_score = ((0.5 - ratio) ** 2) * 5 + 1
        temp_penalty = 0
        penalty_count = 0
        for offset in range(-5, 6):
            idx = i + offset
            if idx < 0 or idx >= n or idx == i:
                continue
            neighbor_cap = bins[idx]
            if neighbor_cap <= 0:
                continue
            dist_factor = 1 / (abs(offset) + 1)
            cap_diff = abs(capacity - neighbor_cap) / max(neighbor_cap, 1e-6)
            temp_penalty += cap_diff * dist_factor
            penalty_count += dist_factor
        if penalty_count > 0:
            temp_penalty /= penalty_count
        adjustment_factor = 1.0
        if capacity < item * 1.2:
            adjustment_factor = 3.5
        elif capacity < item * 1.5:
            adjustment_factor = 2.5
        elif capacity < item * 2:
            adjustment_factor = 1.8
        else:
            adjustment_factor = 1.0 + (capacity - item * 2) / (item * 5)
        score = base_score * adjustment_factor + temp_penalty * 2
        if i % 2 == 0:
            for d in range(1, 4):
                idx = i - d
                if idx < 0:
                    break
                neighbor = bins[idx]
                if neighbor > 0:
                    score -= 0.1 * (d ** 2) * (item / neighbor)
            for d in range(1, 4):
                idx = i + d
                if idx >= n:
                    break
                neighbor = bins[idx]
                if neighbor > 0:
                    score -= 0.1 * (d ** 2) * (item / neighbor)
        if score < 0:
            score = 0
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_finite = np.max(finite_priorities)
    for i in range(n):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_finite * 10 + i * 0.01
    return priorities
